    public List<SystemResponseEventResponse> getSystemResponseEvents(
            TransactionReceipt transactionReceipt) {
        List<Contract.EventValuesWithLog> valueList = extractEventParametersWithLog(SYSTEMRESPONSE_EVENT, transactionReceipt);
        ArrayList<SystemResponseEventResponse> responses = new ArrayList<SystemResponseEventResponse>(valueList.size());
        for (Contract.EventValuesWithLog eventValues : valueList) {
            SystemResponseEventResponse typedResponse = new SystemResponseEventResponse();
            typedResponse.log = eventValues.getLog();
            typedResponse._from = (String) eventValues.getIndexedValues().get(0).getValue();
            typedResponse._result = (Boolean) eventValues.getNonIndexedValues().get(0).getValue();
            typedResponse._msg = (String) eventValues.getNonIndexedValues().get(1).getValue();
            typedResponse._token = (Token) eventValues.getNonIndexedValues().get(2);
            typedResponse._timestamp = (BigInteger) eventValues.getNonIndexedValues().get(3).getValue();
            responses.add(typedResponse);
        }
        return responses;
    }

