    public static SmartLink deploy(Client client, CryptoKeyPair credential, String _sa, String _sc,
                                   String _temc, String _factoryAdd) throws ContractException {
        byte[] encodedConstructor = FunctionEncoder.encodeConstructor(Arrays.<Type>asList(new org.fisco.bcos.sdk.v3.codec.datatypes.Address(_sa),
                new org.fisco.bcos.sdk.v3.codec.datatypes.Address(_sc),
                new org.fisco.bcos.sdk.v3.codec.datatypes.Address(_temc),
                new org.fisco.bcos.sdk.v3.codec.datatypes.Address(_factoryAdd)));
        return deploy(SmartLink.class, client, credential, getBinary(client.getCryptoSuite()), getABI(), encodedConstructor, null);
    }

